const https = require('https');
const http = require('http');
const { JSDOM } = require('jsdom');

exports.fetchUrlMetadata = async (req, res) => {
  const url = req.query.url;
  if (!url) {
    res.status(400).send('URL is required');
    return;
  }

  const fetchData = (url) => {
    return new Promise((resolve, reject) => {
      const client = url.startsWith('https') ? https : http;
      client.get(url, (response) => {
        let data = '';
        
        response.on('data', (chunk) => data += chunk);
        response.on('end', () => resolve(data));
      }).on('error', (error) => reject(error));
    });
  };

  const extractMetadata = (html) => {
    const dom = new JSDOM(html);
    const { document } = dom.window;
    
    const getMetaContent = (property) => {
      const metaTag = document.querySelector(`meta[property='${property}']`) || document.querySelector(`meta[name='${property}']`);
      return metaTag ? metaTag.content : null;
    };

    return {
      title: document.querySelector('title') ? document.querySelector('title').textContent : null,
      description: getMetaContent('description'),
      'og:title': getMetaContent('og:title'),
      'og:description': getMetaContent('og:description'),
      'og:image': getMetaContent('og:image'),
      'og:url': getMetaContent('og:url')
    };
  };

  try {
    const htmlData = await fetchData(url);
    const metadata = extractMetadata(htmlData);
    res.status(200).json(metadata);
  } catch (error) {
    res.status(500).send('Error fetching URL metadata');
  }
};